async def debug_loop(task: str, repo_path: str, max_iterations: int = 5):
    context = await load_repo_context(repo_path)

    for i in range(max_iterations):
        proposal = await coding_agent.run(f"""
        Task: {task}
        Repo context: {context}
        {'Previous failure: ' + failure if 'failure' in locals() else ''}
        """)

        exec_result = await execute_code(proposal.code, proposal.tests)

        if exec_result['passed']:
            return proposal

        failure = exec_result['stderr']

    raise ValueError('Max iterations exceeded')

import re
from pydantic_ai import tool

SECURITY_PATTERNS = [
    r'subprocess\.(call|run|check_call|check_output)',
    r'__import__\("os"\)',
    r'open\([^,]*"w"\)',
    r'exec\(|eval\('  
]

@tool
def scan_security(code: str) -> dict:
    vulnerabilities = []
    for pattern in SECURITY_PATTERNS:
        if re.search(pattern, code):
            vulnerabilities.append(pattern)

    return {
        'clean': len(vulnerabilities) == 0,
        'issues': vulnerabilities
    }
